// @mui
import { styled } from '@mui/material/styles';
// components
import Page from '../../components/Page';
import * as Yup from 'yup';
import { useFormik, Form, FormikProvider } from 'formik';
// sections
import {Box,Typography ,Stack,ButtonBase} from "@mui/material"
import axios from "../../utils/axios";
import api from "../../utils/api";
import Footer from '../../components/onboarding/footer'
import {useNavigate,useLocation} from "react-router"
import TextField from "../../components/core/LabeledInput"
import PasswordField from "../../components/core/PasswordInput"
// ----------------------------------------------------------------------
import Header from "../../components/onboarding/header"
import {updateFeedback} from "../../redux/actions/feedback"
import { useDispatch } from 'react-redux';
import { updateOnboarding } from '../../redux/actions/Onboarding';
import Container from "../../components/Layout/Container"
import FooterBase from "../../components/Layout/Footer"
import Content from "../../components/Layout/Content"
import HeaderBase from "../../components/Layout/Header"
const RootStyle = styled('div')(() => ({
display:"flex",
flexDirection:"column",
flex:1,
flexGrow:1,
height:"100vh"
}));

const BoxStyle=styled(Box)(()=>({
position:"relative"
}))

const InsideBoxStyle=styled(Box)(()=>({
    position:"absolute",
    width:"100%",
    display:"flex",
    justifyContent:"center",
    alignItems:"center",
    flexDirection:"column",
    paddingTop:52,
    paddingBottom:24,
    zIndex:100,
    top:0,
    }))


// ----------------------------------------------------------------------

export default function HomePage() {
const dispatch=useDispatch()
const {state} = useLocation();
  const rePass = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?])[A-Za-z\d!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]{8,}$/;

  const RegisterSchema = Yup.object().shape({

    email: Yup.string().email('Email must be a valid email address').required('Email is required'),
    password: Yup.string()
      .required('Password is required')

      .matches(
        rePass,
        'Minimum eight characters, at least one uppercase letter, one lowercase letter, one number and one special character'
      ),

      confirmPass: Yup.string()
      .required("confirm password is required")
      .oneOf([Yup.ref("password"), null], "Passwords must match")

  });


  const formik = useFormik({
    initialValues: {

      email:"",
      password: "",
      confirmPass:""

    },
    validationSchema: RegisterSchema,
    onSubmit: async (values, { setErrors, setSubmitting }) => {
      
      setSubmitting(true);
      dispatch(updateFeedback({
        loading: true,
      
      }));
      axios
          .post(`${api.protocol}${api.baseUrl}${api.SendVerifyMail}`, {
            email: values.email,
          })
          .then((response) => {

            dispatch(updateOnboarding({
              authType: 1,
              email: values.email,
              password:values.password,
              type: null,
            }))


            dispatch(updateFeedback({
              loading: false,
              snackbar: true,
              message: "Verification mail sent to your email!",
              severity: "success",
            }));
            navigate("/onboarding/verification",{state})

           
          })
          .catch((error) => {
            if (error.response.status === 406)
              return dispatch(updateFeedback({
                loading: false,
                snackbar: true,
                message: "Acccount with give email address already exists!",
                severity: "error",
              }))
            else
              return dispatch(updateFeedback({
                loading: false,
                snackbar: true,
                message: "Oops caught some error! Please try again",
                severity: "error",
              }))
          });
    },
  });

  const navigate=useNavigate()
  const { errors, touched, handleSubmit, isSubmitting, getFieldProps, setFieldValue, values } = formik;
  return (
    <Page title="The starting point for your next fitness gig">
       <FormikProvider value={formik}>
      <Form autoComplete="off" noValidate onSubmit={handleSubmit}>
      <Container>
        <HeaderBase>  <Header title={"Create new account"} /></HeaderBase>
<Content>
   
       <Box display={"flex"}   flexDirection={"column"} alignItems={"center"} px={2} flexGrow={"1"}>


     <Typography variant='h2' color={"primary"} sx={{my:6}}>Hello Coach 👋</Typography>

    <Stack spacing={2} sx={{width:"100%"}}>
     <TextField fullWidth placeholder=""
      clabel="Your email address*"
      {...getFieldProps('email')}
      error={Boolean(touched.email && errors.email)}
      helperText={touched.email && errors.email}/>
       <PasswordField clabel="Password" fullWidth placeholder=""
       {...getFieldProps('password')}
      error={Boolean(touched.password && errors.password)}
      helperText={touched.password && errors.password}/>
       <PasswordField clabel="Confirm Password" fullWidth placeholder=""
        {...getFieldProps('confirmPass')}
        error={Boolean(touched.confirmPass && errors.confirmPass)}
        helperText={touched.confirmPass && errors.confirmPass}/>
       </Stack>
       </Box>
       </Content>
       <FooterBase>
        <Footer  next />
        </FooterBase>
      </Container>
      </Form>
      </FormikProvider>
    </Page>
  );
}


